#include<bits/stdc++.h>
#define long long ll;
using namespace std;
const int N = 1000005;
struct Edge {
	int h, bh;
} a[N];
bool cmp(Edge x, Edge y) {
	return x.h > y.h;
}
int sum[N], n;
int lowbit(int x) {
	return x & -x;
}
void update(int x, int k) {
	for(; x <= n; x += lowbit(x)) sum[x] += k;
}
int getsum(int x) {
	int ans = 0;
	for(; x; x -= lowbit(x)) ans += sum[x];
	return ans;
}
signed main() {
	cin >> n;
	for(int i = 1; i <= n; i++) {
		cin >> a[i].h;
		a[i].bh = i;
	}
	sort(a + 1, a + 1 + n, cmp);
	int ans = 0;
	for(int i = 1; i <= n; i++) {
		update(a[i].bh, 1);
		int l = getsum(a[i].bh - 1);
		int r = i - l - 1;
		if(max(l, r) > 2 * min(l, r)) ans++;
	}
	cout<<ans;
}
